settings.custom_liquid:
{%- if product.metafields.custom.lien_affiliation == blank -%}
  <div class="block-expediteur">
    <span>
      Expédié par 
      <a href="https://verty.eu/pages/la-procure-vendeur-et-partenaire-de-verty" 
         target="_blank" 
         class="lien-procure hover-highlight">
         La Procure
      </a>
    </span>
  </div>

  <style>
    .block-expediteur .lien-procure {
      color: #8FCDBF;
font-weight : 900;
      text-decoration: none; /* retire le soulignement */
    }
    .block-expediteur .lien-procure:hover {
      text-decoration: underline; /* si tu veux un soulignement au survol */
    }
  </style>
{%- else -%}
  <style>
   .product-info__block > .block-expediteur {
      display: none;
   }
  </style>
{%- endif -%}
